	.sub-menu .menu-ul{width:100%}
	.sub-menu .menu-ul li{list-style:disc;list-style-position:outside;padding:0 15px 5px 0}
	.lex-search-div{width:95%}
	.lex-search-div .lex-s-range{width:70px}
